		}

		.list-table li[class*="row"].muted {
			background: none;
			color: #aaa
		}

		.list-table li[class*="row"].muted .range-opacity {
			background: #666;
			opacity: .1;
			filter: alpha(opacity=10)
		}

		.list-table .range-bar {
			display: table-cell;
			position: absolute;
			top: 0;
			left: 0;
			width: 100%;
			height: 100%;
			z-index: 0;
			padding: 0;
			margin: 0
		}

		.list-table .range-bar .range {
			position: relative;
			height: 69px;
			padding: 0;
			margin: 0;
			display: inline-block;
			float: left;
			overflow: hidden
		}

		.list-table ul[class*="properties"] {
			*zoom: 1;
			position: relative;
			z-index: 2;
			padding: 14px;
			height: 40px;
			line-height: 18px
		}

		.list-table ul[class*="properties"]:before,
		.list-table ul[class*="properties"]:after {
			display: table;
			content: ""
