		@-webkit-keyframes pulse {
			0% {
				-webkit-transform: scale(.4);
				-moz-transform: scale(.4);
				-ms-transform: scale(.4);
				transform: scale(.4);
				opacity: .5
			}

			50% {
				-webkit-transform: scale(1);
				-moz-transform: scale(1);
				-ms-transform: scale(1);
				transform: scale(1);
				opacity: 1
			}

			100% {
				-webkit-transform: scale(.4);
				-moz-transform: scale(.4);
				-ms-transform: scale(.4);
				transform: scale(.4);
				opacity: .5
			}
		}

		@keyframes pulse {
			0% {
				-webkit-transform: scale(.4);
				-moz-transform: scale(.4);
				-ms-transform: scale(.4);
				transform: scale(.4);
				opacity: .5
			}

			50% {
				-webkit-transform: scale(1);
				-moz-transform: scale(1);
				-ms-transform: scale(1);
				transform: scale(1);
				opacity: 1
			}

			100% {
				-webkit-transform: scale(.4);
				-moz-transform: scale(.4);
				-ms-transform: scale(.4);
				transform: scale(.4);
				opacity: .5
			}
		}

		.wizard-point {
			width: 80px;
			height: 80px;
			-webkit-border-radius: 80px;
			-moz-border-radius: 80px;
			border-radius: 80px;
			border: 4px solid #5daede;
			-webkit-box-shadow: 0 0 25px rgba(255, 255, 255, .9);
			-moz-box-shadow: 0 0 25px rgba(255, 255, 255, .9);
			box-shadow: 0 0 25px rgba(255, 255, 255, .9);
			position: absolute;
			z-index: 9998;
			opacity: .5;
			background: transparent;
			-webkit-transform: scale(.8);
			-moz-transform: scale(.8);
			-ms-transform: scale(.8);
			transform: scale(.8);
			-webkit-animation: pulse 1s ease-in-out infinite;
			-moz-animation: pulse 1s ease-in-out infinite;
			animation: pulse 1s ease-in-out infinite
		}

